mapper.select:
SELECT
site_code          AS siteCode,
agent_id           AS agentId,
plan_rate          AS planRate,
venue_type         AS venueType,
SUM(valid_amount)  AS validAmount,
SUM(commission_amount) AS commissionAmount
FROM agent_commission_venue_report
WHERE site_code = #{siteCode}


    AND agent_id IN

        #{aid}




    AND commission_type = #{commissionType}




    AND start_time >= #{startTime}



    AND end_time <= #{endTime}


GROUP BY site_code, agent_id, plan_rate, venue_type
ORDER BY venue_type

SELECT count(1)  FROM agent_info_relation	 WHERE   site_code = #{siteCode}
                                                       AND ancestor_agent_id = #{agentId}
                                                       AND start_time >= #{startTime}
                                                       AND end_time <= #{endTime}  and agent_depth>0

SELECT count(1) FROM user_info WHERE  site_code = #{siteCode}
                                 AND super_agent_id= #{agentId}
                                 AND start_time >= #{startTime}
                                 AND end_time <= #{endTime}

SELECT IFNULL(SUM(r.commission_amount), 0) AS commissionAmount
FROM agent_info_relation rel
         JOIN agent_commission_venue_report r
              ON r.agent_id = rel.descendant_agent_id
WHERE rel.ancestor_agent_id = #{agentId}
  AND rel.agent_depth = 1
  AND r.site_code = #{siteCode}
  AND r.start_time >= #{startTime}
  AND r.end_time <= #{endTime}

SELECT *
FROM agent_commission_venue_report
WHERE site_code = #{siteCode}
  AND agent_id = #{agentId}
  AND start_time >= #{startTime}
  AND end_time <= #{endTime}

SELECT IFNULL(SUM(r.commission_amount), 0) AS commissionAmount
FROM agent_info_relation rel
         JOIN agent_commission_venue_report r
              ON r.agent_id = rel.descendant_agent_id
WHERE rel.ancestor_agent_id = #{agentId}
  AND rel.agent_depth > 1
  AND r.site_code = #{siteCode}
  AND r.start_time >= #{startTime}
  AND r.end_time <= #{endTime}
